28	/**@ch 懸賞令管理器事件*/
29	export const WANTED_POSTER_MANAGER_EVENT = {
30	    /**
31	     * @ch 設置懸賞令資料
32	     * @param IBountyData[] 懸賞令資料陣列
33	     */
34	    SET_WANTED_POSTER_DATA: "WANTED_POSTER_MANAGER_SET_WANTED_POSTER_DATA",
35	
36	    /**
37	     * @ch 設置懸賞令UI顯示狀態
38	     * @param isShow 是否顯示
39	     */
40	    SET_WANTED_POSTER_UI_SHOW: "WANTED_POSTER_MANAGER_SET_WANTED_POSTER_UI_SHOW",
41	
42	    /**
43	     * @ch 對 BaseSymbol 對應的常駐 item 播 Mark → Mark_Idle loop
44	     * @param baseSymbol number 對應的 BaseSymbol（M1~M9）
45	     * @param resolve () => void 播完 Mark 後呼叫（Mark_Idle 已在 spine 上 loop）
46	     */
47	    PLAY_MARK: "WANTED_POSTER_MANAGER_PLAY_MARK",
48	
49	    /**
50	     * @ch 對 BaseSymbol 對應的常駐 item 播 Mark_Active 並關閉 item
51	     * @param baseSymbol number 對應的 BaseSymbol
52	     * @param resolve () => void 播完 Mark_Active 且 item.active=false 後呼叫
53	     */
54	    PLAY_MARK_ACTIVE: "WANTED_POSTER_MANAGER_PLAY_MARK_ACTIVE",
55	    
56	    /**
57	     * @ch 遊戲介紹完成後顯示懸賞令x9999
58	     */
59	    GAME_INTRO_COMPLETE: "WANTED_POSTER_MANAGER_GAME_INTRO_COMPLETE",
60	}
61	
62	/**@ch 懸賞令管理器*/
63	@ccclass('WantedPosterManager')
64	export class WantedPosterManager extends Component {
65	    //#region Constants
66	    /**
67	     * @ch 需要註冊的事件列表
68	     */
69	    private static readonly EVENTS_TO_REGISTER = [
70	        WANTED_POSTER_MANAGER_EVENT.SET_WANTED_POSTER_DATA,
71	        WANTED_POSTER_MANAGER_EVENT.SET_WANTED_POSTER_UI_SHOW,
72	        WANTED_POSTER_MANAGER_EVENT.PLAY_MARK,
73	        WANTED_POSTER_MANAGER_EVENT.PLAY_MARK_ACTIVE,
74	        WANTED_POSTER_MANAGER_EVENT.GAME_INTRO_COMPLETE,
75	        GAME_EVENT.DEVICE_ROTATION,
76	    ];
77	    //#endregion Constants
78	
79	    //#region Properties
80	    @property({
81	        type: Node,
82	        tooltip: "根節點"
83	    })
84	    private m_rootNode: Node = null;
85	
86	    @property({
87	        type: [WantedPosterItem],
88	        tooltip: "懸賞令物品"
89	    })
90	    private m_wantedPosterItems: WantedPosterItem[] = [];
91	
92	    @property({
93	        type: Layout,
94	        tooltip: "懸賞令排版元件（m_wantedPosterItems 父節點上的 cc.Layout）"
95	    })
96	    private m_layout: Layout = null;
97	
98	    @property({
99	        type: WantedPosterLayoutConfig,
100	        tooltip: "直向排版設定"
101	    })
102	    private m_portraitConfig: WantedPosterLayoutConfig = new WantedPosterLayoutConfig();
103	
104	    @property({
105	        type: WantedPosterLayoutConfig,
106	        tooltip: "橫向排版設定"
107	    })
108	    private m_landscapeConfig: WantedPosterLayoutConfig = new WantedPosterLayoutConfig();
109	    //#endregion Properties
110	
111	    //#region Variables
112	    /**@ch 是否已初始化*/
113	    private m_isInitialized: boolean = false;
114	
115	    /**
116	     * @ch 各 item 目前綁定的懸賞令資料（null = 該 item 未顯示）
117	     * 與 m_wantedPosterItems 同索引，是「同 BaseSymbol 持續判斷」與「倍率是否變」的真實依據
118	     * （item 本身只記 BaseSymbol、不記 Multiple，故由 Manager 統一追蹤）
119	     */
120	    private m_currentBounty: (IBountyData | null)[] = [];
121	    //#endregion Variables
122	
123	    //#region Lifecycle
124	    /**@ch 元件載入時調用*/
125	    onLoad() {
126	        this.RegisterEvent();
127	        this.RegisterKeyboardEvents();
128	        this.EnsureCurrentBountySize();
129	    }
130	
131	    /**@ch 元件啟動時調用（GameView 已就緒，套用初始方向 Layout）*/
132	    start() {
133	        this.ApplyLayoutByOrientation();
134	    }
135	
136	    /**@ch 元件銷毀時調用*/
137	    onDestroy() {
138	        if (!this.m_isInitialized) return;
139	        this.UnregisterEvent();
140	        this.UnregisterKeyboardEvents();
141	        this.m_isInitialized = false;
142	    }
143	    //#endregion Lifecycle
144	
145	    //#region Event Management
146	    /**@ch 註冊鍵盤事件（測試用）*/
147	    private RegisterKeyboardEvents(): void {
148	        if (!DEBUG) return;
149	        // input.on(Input.EventType.KEY_DOWN, this.CheckTestKeyCode, this);
150	    }
151	
152	    /**@ch 取消註冊鍵盤事件（測試用）*/
153	    private UnregisterKeyboardEvents(): void {
154	        if (!DEBUG) return;
155	        // input.off(Input.EventType.KEY_DOWN, this.CheckTestKeyCode, this);
156	    }
157	
158	    /**@ch 註冊事件*/
159	    private RegisterEvent() {
160	        WantedPosterManager.EVENTS_TO_REGISTER.forEach(eventName => {
161	            eventManager.Register(eventName, this);
162	        });
163	        this.m_isInitialized = true;
164	    }
165	
166	    /**@ch 取消註冊事件*/
167	    private UnregisterEvent() {
168	        WantedPosterManager.EVENTS_TO_REGISTER.forEach(eventName => {
169	            eventManager.UnRegister(eventName, this);
170	        });
171	    }
172	
173	    /**
174	     * @ch 驗證 SET_WANTED_POSTER_UI_SHOW 事件參數
175	     * @param args 事件參數
176	     * @returns 是否有效
177	     */
178	    private ValidateSetWantedPosterUIShowArgs(args: any[]): boolean {
179	        if (typeof args[0] !== 'boolean') {
180	            warn('[WantedPosterManager] SET_WANTED_POSTER_UI_SHOW: 無效的參數', args[0]);
181	            return false;
182	        }
183	        return true;
184	    }
185	
186	    /**
187	     * @ch 驗證 SET_WANTED_POSTER_DATA 事件參數
188	     * @param args 事件參數
189	     * @returns 是否有效
190	     */
191	    private ValidateSetWantedPosterDataArgs(args: any[]): boolean {
192	        if (!Array.isArray(args[0])) {
193	            warn('[WantedPosterManager] SET_WANTED_POSTER_DATA: 無效的資料參數', args[0]);
194	            return false;
195	        }
196	        return true;
197	    }
198	
199	    /**
200	     * @ch 事件回調
201	     * @param event 事件名稱
202	     * @param args 事件參數
203	     */
204	    OnEvent(event: string, ...args: any[]) {
205	        switch (event) {
206	            case WANTED_POSTER_MANAGER_EVENT.SET_WANTED_POSTER_DATA:
207	                if (this.ValidateSetWantedPosterDataArgs(args)) {
208	                    this.SetWantedPosterData(
209	                        args[0] as IBountyData[],
210	                        args[1] === true,
211	                        Array.isArray(args[2]) ? args[2] as number[] : undefined
212	                    );
213	                }
214	                break;
215	
216	            case WANTED_POSTER_MANAGER_EVENT.SET_WANTED_POSTER_UI_SHOW:
217	                if (this.ValidateSetWantedPosterUIShowArgs(args)) {
218	                    this.SetWantedPosterUIShow(args[0] as boolean);
219	                }
220	                break;
221	
222	            case WANTED_POSTER_MANAGER_EVENT.PLAY_MARK:
223	                this.HandlePlayMark(args[0] as number, args[1] as () => void);
224	                break;
225	
226	            case WANTED_POSTER_MANAGER_EVENT.PLAY_MARK_ACTIVE:
227	                this.HandlePlayMarkActive(args[0] as number, args[1] as () => void);
228	                break;
229	
230	            case WANTED_POSTER_MANAGER_EVENT.GAME_INTRO_COMPLETE:
231	                this.HandleGameIntroComplete();
232	                break;
233	
234	            case GAME_EVENT.DEVICE_ROTATION:
235	                this.ApplyLayoutByOrientation();
236	                break;
237	
238	            default:
239	                warn('[WantedPosterManager] OnEvent: 未知的事件', event);
240	        }
241	    }
242	
243	    /**
244	     * @ch 依目前裝置方向套用對應的 Layout 設定
245	     * 由 start() 與 GAME_EVENT.DEVICE_ROTATION 事件觸發
246	     */
247	    private ApplyLayoutByOrientation(): void {
248	        if (!this.m_layout) {
249	            warn('[WantedPosterManager] ApplyLayoutByOrientation: m_layout 未設置');
250	            return;
251	        }
252	        const isLandscape = Common.GetGameView().IsLandscape;
253	        const cfg = isLandscape ? this.m_landscapeConfig : this.m_portraitConfig;
254	
255	        this.m_layout.type = cfg.type;
256	        this.m_layout.resizeMode = cfg.resizeMode;
257	        this.m_layout.paddingLeft = cfg.paddingLeft;
258	        this.m_layout.paddingRight = cfg.paddingRight;
259	        this.m_layout.paddingTop = cfg.paddingTop;
260	        this.m_layout.paddingBottom = cfg.paddingBottom;
261	        this.m_layout.spacingX = cfg.spacingX;
262	        this.m_layout.spacingY = cfg.spacingY;
263	        this.m_layout.alignHorizontal = cfg.alignHorizontal;
264	        this.m_layout.alignVertical = cfg.alignVertical;
265	        this.m_layout.updateLayout();
266	    }
267	
268	    /**
269	     * @ch 處理 PLAY_MARK 事件
270	     * BC-4：對該 BaseSymbol 的所有相符常駐 item 同時播 Mark，全部完成才 resolve
271	     *       （找到 N 個就播 N 個；N=0 才視為 EH-1，0<N 屬可接受降級不 warn）
272	     * EH-1：找不到任何對應 item（空陣列）→ warn + 立刻 resolve（不阻斷上游流程）
273	     * EH-9：resolve callback 缺失 → error（caller bug）
274	     */
275	    private HandlePlayMark(baseSymbol: number, resolve: () => void) {
276	        if (typeof resolve !== 'function') {
277	            warn('[WantedPosterManager] PLAY_MARK: resolve callback 缺失');
278	            return;
279	        }
280	        const items = this.GetItemsByBaseSymbol(baseSymbol);
281	        if (items.length === 0) {
282	            warn('[WantedPosterManager] PLAY_MARK: 找不到對應 item, baseSymbol=', baseSymbol);
283	            resolve();
284	            return;
285	        }
286	        Promise.all(items.map(item => item.PlayMark())).then(() => resolve());
287	    }
288	
289	    /**
290	     * @ch 處理 PLAY_MARK_ACTIVE 事件
291	     * BC-6：對該 BaseSymbol 的所有相符 item 同時播 Mark_Active 並各自 active=false
292	     * EH-1：找不到任何對應 item（空陣列）→ warn + 立刻 resolve
293	     * EH-9：resolve callback 缺失 → error
294	     */
295	    private HandlePlayMarkActive(baseSymbol: number, resolve: () => void) {
296	        if (typeof resolve !== 'function') {
297	            warn('[WantedPosterManager] PLAY_MARK_ACTIVE: resolve callback 缺失');
298	            return;
299	        }
300	        const items = this.GetItemsByBaseSymbol(baseSymbol);
301	        if (items.length === 0) {
302	            warn('[WantedPosterManager] PLAY_MARK_ACTIVE: 找不到對應 item, baseSymbol=', baseSymbol);
303	            resolve();
304	            return;
305	        }
306	        Promise.all(items.map(item =>
307	            item.PlayMarkActive().then(() => {
308	                item.node.active = false;
309	                // 收尾關閉 item → 同步清除綁定，避免與 m_currentBounty 失同步
310	                const idx = this.m_wantedPosterItems.indexOf(item);
311	                if (idx >= 0) this.m_currentBounty[idx] = null;
312	            })
313	        )).then(() => resolve());
314	    }
315	
316	    /**
317	     * @ch 處理 GAME_INTRO_COMPLETE 事件
318	     * 遊戲介紹完成後顯示 1 個懸賞令（M1、倍率 9999）為「已定位」靜止畫面（不播 In 進場）。
319	     * 前提：呼叫時場上保證為空（開場第一次顯示），故直接設定 item[0]、不需清場。
320	     * Multiple=9999 ≥ Multiplier_Max → item 內部走 m_x9999Node 顯示分支。
321	     */
322	    private HandleGameIntroComplete() {
323	        this.EnsureCurrentBountySize();
324	        const item = this.m_wantedPosterItems[0];
325	        if (!item) {
326	            warn('[WantedPosterManager] GAME_INTRO_COMPLETE: 懸賞令物品[0] 未設置');
327	            return;
328	        }
329	        const data: IBountyData = { BaseSymbol: Symbol.M1, BountySymbol: 0, Multiple: 9999, MultipleIndex: 0 };
330	        item.SetWantedPosterData(data);
331	        item.node.active = true;
332	        item.ShowInSettled();           // 直接顯示 In 定位完成的靜止畫面（不播進場）
333	        this.m_currentBounty[0] = data;
334	    }
335	    //#endregion Event Management
336	
337	    //#region Methods
338	    /**
339	     * @ch 設置懸賞令資料（以 BaseSymbol multiset 比對前後狀態 — 決定 進場 / 退場 / 退場再進場 / 持續）
340	     *
341	     * 比對規則（內容式，計數 multiset；每個 BaseSymbol 綁定一個 item，持續者保留原綁定）：
342	     * - BC-20 isNewRound=true（新一局）→ 現有全部退場、新清單全部進場（整批重建）
343	     * - BC-21 同局・新增 BaseSymbol（計數增加）→ 進場（SetData + active + PlayIn）
344	     * - BC-22 同局・移除 BaseSymbol（計數減少）→ 退場（PlayOut → active=false）
345	     * - BC-23 同局・同 BaseSymbol・Multiple 變 → 原 item 退場再進場（PlayOut → SetData → PlayIn）
346	     * - BC-24 同局・同 BaseSymbol・Multiple 同・盤面(扣除被消除位置)已無此符號 → 原 item 退場再進場
347	     * - BC-25 同局・同 BaseSymbol・Multiple 同・盤面仍可見 → 持續，不播動畫
348	     * 位置重排一律交由 cc.Layout（本元件只處理 In/Out 動畫，不碰節點位置）。
349	     *
350	     * @param dataList 本輪懸賞令資料（Multiple>0 才顯示）
351	     * @param isNewRound 是否新一局（強制整批重建）；省略視為同局 cascade
352	     * @param visibleBaseSymbols 盤面(扣除被消除位置)目前可見的 BaseSymbol；僅 cascade 需傳，省略視為全可見
353	     */
354	    private SetWantedPosterData(dataList: IBountyData[], isNewRound: boolean = false, visibleBaseSymbols?: number[]) {
355	        if (!this.m_wantedPosterItems || this.m_wantedPosterItems.length === 0) {
356	            warn('[WantedPosterManager] SetWantedPosterData: 懸賞令物品未設置');
357	            return;
358	        }
359	        this.EnsureCurrentBountySize();
360	
361	        const count = this.m_wantedPosterItems.length;
362	        // 本輪要顯示的 bounty（Multiple>0），超量截斷至 item 數量上限
363	        const newBounties = dataList.filter(d => d && d.Multiple > 0);
364	        if (newBounties.length > count) {
365	            warn('[WantedPosterManager] SetWantedPosterData: 資料數量超過物品數量',
366	                newBounties.length, '>', count);
367	            newBounties.length = count;
368	        }
369	
370	        if (isNewRound) {
371	            this.RebuildAll(newBounties);
372	        } else {
373	            this.ReconcileCascade(newBounties, visibleBaseSymbols);
374	        }
375	    }
376	
377	    /**
378	     * @ch BC-20 整批重建（新一局）：現有全部 Out 並關閉，全部 Out 完成後新清單依序設資料、active、PlayIn。
379	     *     先 Out 再一起 In，避免新舊同時在場造成 Layout 重排跳動。
380	     *     綁定同步記錄為目標狀態（視覺在 Out 完成後才 In）。
381	     */
382	    private RebuildAll(newBounties: IBountyData[]) {
383	        const count = this.m_wantedPosterItems.length;
384	
385	        const outPromises: Promise<void>[] = [];
386	        for (let i = 0; i < count; i++) {
387	            const item = this.m_wantedPosterItems[i];
388	            if (item && item.node.active) {
389	                outPromises.push(item.PlayOut().then(() => { item.node.active = false; }));
390	            }
391	            // 同步記錄目標綁定（前 newBounties.length 個為新資料，其餘清空）
392	            this.m_currentBounty[i] = i < newBounties.length ? newBounties[i] : null;
393	        }
394	
395	        const enterAll = () => {
396	            for (let i = 0; i < newBounties.length; i++) {
397	                const item = this.m_wantedPosterItems[i];
398	                if (!item) continue;
399	                item.SetWantedPosterData(newBounties[i]);
400	                item.node.active = true;
401	                item.PlayIn();
402	            }
403	        };
404	
405	        if (outPromises.length > 0) Promise.all(outPromises).then(enterAll);
406	        else enterAll();
407	    }
408	
409	    /**
410	     * @ch 同局 cascade 對帳：以 BaseSymbol multiset 比對目前綁定 ↔ 新清單，保留持續者的 item 綁定。
411	     *     - 同 BaseSymbol・Multiple 同・盤面仍可見 → 持續（不動）         [BC-25]
412	     *     - 同 BaseSymbol・Multiple 變 或 盤面已無此符號 → 原 item 退場再進場 [BC-23/BC-24]
413	     *     - 多出的新 BaseSymbol → 進場（優先用原本就空的 item；不足才等退場者騰出版位）[BC-21]
414	     *     - 少掉的舊 BaseSymbol → 退場                                  [BC-22]
415	     * @param visibleBaseSymbols 盤面(扣除被消除位置)可見的 BaseSymbol；省略視為全可見
416	     */
417	    private ReconcileCascade(newBounties: IBountyData[], visibleBaseSymbols?: number[]) {
418	        const count = this.m_wantedPosterItems.length;
419	        const visible = visibleBaseSymbols ? new Set(visibleBaseSymbols) : null;
420	
421	        // 新清單依 BaseSymbol 分組成可消耗的 pool（multiset）
422	        const pool = new Map<number, IBountyData[]>();
423	        for (const b of newBounties) {
424	            const list = pool.get(b.BaseSymbol);
425	            if (list) list.push(b); else pool.set(b.BaseSymbol, [b]);
426	        }
427	
428	        const preFreeSlots: number[] = [];      // 更新前就空著的 item，供進場立即使用
429	        const vacatingSlots: number[] = [];     // 本輪退場騰出的 item，Out 完才可用
430	        const outPromises: Promise<void>[] = [];
431	        const deferredEnter: IBountyData[] = [];
432	
433	        // Pass A：逐一決定目前已綁定 item 的命運
434	        for (let i = 0; i < count; i++) {
435	            const cur = this.m_currentBounty[i];
436	            const item = this.m_wantedPosterItems[i];
437	            if (cur === null) {
438	                if (item) preFreeSlots.push(i);
439	                continue;
440	            }
441	            const bs = cur.BaseSymbol;
442	            const list = pool.get(bs);
443	            if (list && list.length > 0) {
444	                const onBoard = visible ? visible.has(bs) : true;
445	                // 優先配對「相同 Multiple」以持續（不播動畫）；盤面不可見則一律退場再進場
446	                const sameIdx = onBoard ? list.findIndex(b => b.Multiple === cur.Multiple) : -1;
447	                if (sameIdx >= 0) {
448	                    list.splice(sameIdx, 1);                 // BC-25 持續：消耗一筆，item 不動
449	                } else {
450	                    const nb = list.shift()!;                // BC-23/BC-24 退場再進場
451	                    if (item) item.PlayOut().then(() => { item.SetWantedPosterData(nb); item.PlayIn(); });
452	                    this.m_currentBounty[i] = nb;
453	                }
454	                if (list.length === 0) pool.delete(bs);
455	            } else {
456	                // BC-22 新清單已無此 BaseSymbol → 退場
457	                if (item) outPromises.push(item.PlayOut().then(() => { item.node.active = false; }));
458	                this.m_currentBounty[i] = null;
459	                vacatingSlots.push(i);
460	            }
461	        }
462	
463	        // Pass B：pool 剩餘 = 需進場的新 BaseSymbol [BC-21]
464	        const remaining: IBountyData[] = [];
465	        for (const list of pool.values()) remaining.push(...list);
466	        for (const nb of remaining) {
467	            if (preFreeSlots.length > 0) {
468	                this.EnterAt(preFreeSlots.shift()!, nb);     // 有現成空位 → 立即進場
469	            } else {
470	                deferredEnter.push(nb);                      // 無現成空位 → 等退場者騰出
471	            }
472	        }
473	
474	        // 不足的進場等所有退場完成後，使用騰出的 item 版位
475	        if (deferredEnter.length > 0) {
476	            Promise.all(outPromises).then(() => {
477	                for (const nb of deferredEnter) {
478	                    const idx = vacatingSlots.shift();
479	                    if (idx === undefined) break;            // 理論上不會（已截斷至 count）
480	                    this.EnterAt(idx, nb);
481	                }
482	            });
483	        }
484	    }
485	
486	    /**@ch 在指定 item 版位進場：設資料、active、PlayIn 並記錄綁定*/
487	    private EnterAt(index: number, data: IBountyData) {
488	        const item = this.m_wantedPosterItems[index];
489	        if (!item) return;
490	        item.SetWantedPosterData(data);
491	        item.node.active = true;
492	        item.PlayIn();
493	        this.m_currentBounty[index] = data;
494	    }
495	
496	    /**@ch 確保綁定追蹤陣列長度與 item 數一致（初次/變動時補 null、保留既有）*/
497	    private EnsureCurrentBountySize() {
498	        const count = this.m_wantedPosterItems.length;
499	        if (this.m_currentBounty.length === count) return;
500	        const next: (IBountyData | null)[] = new Array(count).fill(null);
501	        const keep = Math.min(this.m_currentBounty.length, count);
502	        for (let i = 0; i < keep; i++) next[i] = this.m_currentBounty[i];
503	        this.m_currentBounty = next;
504	    }
505	
506	    /**
507	     * @ch 依 BaseSymbol 取得**所有**相符的 active 常駐 item（內部用，PLAY_MARK / PLAY_MARK_ACTIVE 路徑）
508	     * 同一盤面允許多筆同 BaseSymbol bounty（各自設到不同 index 的 item），故回陣列而非單一
509	     */
510	    private GetItemsByBaseSymbol(baseSymbol: number): WantedPosterItem[] {
511	        if (baseSymbol === null || baseSymbol === undefined) return [];
512	        const result: WantedPosterItem[] = [];
513	        for (const item of this.m_wantedPosterItems) {
514	            if (item && item.node.active && item.GetBaseSymbol() === baseSymbol) {
515	                result.push(item);
516	            }
517	        }
518	        return result;
519	    }
520	    /**
521	     * @ch 設置懸賞令 UI 顯示狀態
522	     * @param isShow 是否顯示
523	     */
524	    private SetWantedPosterUIShow(isShow: boolean) {
525	        if (!this.m_rootNode) {
526	            warn('[WantedPosterManager] SetWantedPosterUIShow: 根節點未設置');
527	            return;
528	        }
529	        this.m_rootNode.active = isShow;
530	    }
531	    //#endregion Methods
532	
533	    //#region 測試功能
534	    /**
535	     * @ch 測試按鍵處理
536	     * - 數字鍵 1：顯示 1 個懸賞令
537	     * - 數字鍵 2：顯示 2 個懸賞令
538	     * - 數字鍵 3：顯示 UI
539	     * - 數字鍵 4：隱藏 UI
540	     */
541	    private CheckTestKeyCode(event: EventKeyboard): void {
542	        if (!DEBUG) return;
543	        switch (event.keyCode) {
544	            case KeyCode.DIGIT_1:
545	                // 測試：顯示 1 個懸賞令
546	                this.SetWantedPosterData([
547	                    { BaseSymbol: Symbol.M1, BountySymbol: 0, Multiple: 2, MultipleIndex: 0 },
548	                ], true);
549	                break;
550	
551	            case KeyCode.DIGIT_2:
552	                // 測試：顯示 2 個懸賞令
553	                this.SetWantedPosterData([
554	                    { BaseSymbol: Symbol.M4, BountySymbol: 0, Multiple: 256, MultipleIndex: 0 },
555	                    { BaseSymbol: Symbol.M8, BountySymbol: 0, Multiple: 9999, MultipleIndex: 1 },
556	                ], true);
557	                break;
558	
559	            case KeyCode.DIGIT_3:
560	                // 測試：顯示 UI
561	                this.SetWantedPosterUIShow(true);
562	                break;
563	
564	            case KeyCode.DIGIT_4:
565	                // 測試：隱藏 UI
566	                this.SetWantedPosterUIShow(false);
567	                break;
568	        }
569	    }
570	    //#endregion 測試功能
571	}
572	
