import { log } from "cc";
import { BaseState, eventManager, stateManager } from "db://astarte-framework/Managers";
import GameView from "../GameView";
import Game_Define from "../Game_Define";
import { WANTED_POSTER_MANAGER_EVENT } from "../WantedPoster/WantedPosterManager";
import { MULTIPLIER_BASE_MANAGER_EVENT } from "../MultBase/MultiplierBaseManager";
import protocol from "@igs-arcade-division-rd2/uk_815_pirates_queen_9999_proto/ar2pq9Proto.js";

export class MatchingPatchUpState extends BaseState
{
    private m_gameView: GameView = null;

    constructor( gameView: GameView )
    {
        super();
        this.m_gameView = gameView;
    }

    public async OnEnter()
    {

        log( "OnEnter State : MATCHING_PATCH_UP" );
        const curRoundInfo = this.m_gameView.RoundInfo;
        const curPlateIndex = this.m_gameView.CurPlateIndex;

        // 回歸守衛：本盤消除後（Explode②ADD + WantedPoster④SET 已全部完成），
        // 被消除位置的乘倍底板 index 應等於 Server 的 BasePlateIndex。不一致只 log，不影響流程。
        const playedPlate = curRoundInfo.PlateQueue[ curPlateIndex ];
        if ( playedPlate?.BasePlateIndex && playedPlate?.EliminatePos )
        {
            eventManager.Dispatch(
                MULTIPLIER_BASE_MANAGER_EVENT.CHECK_MULTIPLIER_WITH_SERVER,
                playedPlate.BasePlateIndex,
                playedPlate.EliminatePos
            );
        }

        if (curPlateIndex >= curRoundInfo.PlateQueue.length-1)
        {
            this.m_gameView.CurPlateIndex++;
            //統一由COUNT_MULT切流程
            stateManager.NextState( Game_Define.GameState.COUNT_MULT);
            return;
        }

        let plateInfo = curRoundInfo.PlateQueue[ curPlateIndex ];
        const nextPlateInfo = curRoundInfo.PlateQueue[ curPlateIndex + 1 ];
        let nextPlateSymbols = nextPlateInfo.PlateSymbol;
        let eliminatePos = plateInfo.EliminatePos;

        // 設置懸賞令資料（cascade → isNewRound=false，附「盤面扣除被消除位置」可見的 BaseSymbol 供持續判斷）
        const bountyDataVec = nextPlateInfo.BountyDataVec ? nextPlateInfo.BountyDataVec : [];
        const visibleBaseSymbols = this.ComputeVisibleBaseSymbols( plateInfo );
        eventManager.Dispatch(WANTED_POSTER_MANAGER_EVENT.SET_WANTED_POSTER_DATA, bountyDataVec, false, visibleBaseSymbols);

        let fillSymbols: number[][] = [];
        let eliminateSymbols: number[][] = [];
        if ( eliminatePos )
        {
            fillSymbols.length = Game_Define.COL;
            eliminateSymbols.length = Game_Define.COL;
            for ( let col = 0; col < Game_Define.COL; col++ )
            {
                eliminateSymbols[col] = [];
                fillSymbols[col] = [];
            }
            for ( let i = 0; i < eliminatePos.length; i++ )
            {
                const { col, row } = this.m_gameView.SlotReels.GetColRowFromPosition(eliminatePos[i]);

                eliminateSymbols[col].push( row );
            }
            for( let col = 0; col < Game_Define.COL; col++ )
            {
                if ( eliminateSymbols[col] )
                {
                    for(let i = eliminateSymbols[col].length-1; i >= 0; i-- )
                    {

                        fillSymbols[col].push( nextPlateSymbols[col].Col[i] );
                    }
                }
            }
        }

        // 天降
        //let fillSymbols = this.m_gameView.ConvertColumn( comboStageInfo.FillSymbols );
        //let fillMults = this.m_gameView.ConvertColumn( comboStageInfo.FillMults );
        // NearWin 時顯示光效（在 TileMatchingAndPatchUp 內部處理）
        await this.m_gameView.SlotReels.TileMatchingAndPatchUp( fillSymbols, null );

        this.m_gameView.CurPlateIndex++;

        // 驗證 cascade 消除補牌後的盤面 == 現在盤面上的 plate（CurPlateIndex 已 ++，等於補牌來源的 next plate）
        const onBoardPlate = curRoundInfo.PlateQueue[ this.m_gameView.CurPlateIndex ];
        if ( onBoardPlate && onBoardPlate.PlateSymbol )
        {
            this.m_gameView.SlotReels.CheckPlateInfo( onBoardPlate.PlateSymbol, "cascade" );
        }

        stateManager.NextState( Game_Define.GameState.COUNT_MULT );
    }    

    public OnProcess()
    {

    }

    public OnLeave()
    {

    }

    /**
     * @ch 計算「當前 plate 扣除被消除位置」後仍可見的 BaseSymbol 集合
     *     供懸賞令判斷同 BaseSymbol 是否仍在玩家盤面上（決定持續或退場再進場）
     * @param plateInfo 當前 plate（含 PlateSymbol 與 EliminatePos）
     */
    private ComputeVisibleBaseSymbols( plateInfo: protocol.ar2pq9Proto.IPlateInfo ): number[]
    {
        const cols = plateInfo?.PlateSymbol;
        if ( !cols ) return [];

        // 被消除位置 → "col,row" 字串集合
        const eliminated = new Set<string>();
        const elim = plateInfo.EliminatePos;
        if ( elim )
        {
            for ( const pos of elim )
            {
                const { col, row } = this.m_gameView.SlotReels.GetColRowFromPosition( pos );
                eliminated.add( `${col},${row}` );
            }
        }

        // 收集所有未被消除位置上的符號
        const result = new Set<number>();
        for ( let col = 0; col < cols.length; col++ )
        {
            const colData = cols[ col ]?.Col;
            if ( !colData ) continue;
            for ( let row = 0; row < colData.length; row++ )
            {
                if ( eliminated.has( `${col},${row}` ) ) continue;
                result.add( colData[ row ] );
            }
        }
        return Array.from( result );
    }
}

