/** 複製原始檔案，並新增 CC 模組匯入 */
import { _decorator, Component, log, Node, warn } from "cc";
import GameView from "./GameView";
import { eventManager } from "db://astarte-framework/Managers";
import { GAME_EVENT } from "./Game_Define";
import { Common } from "./Common/Common";
import { BaseSpine } from "./Spine/BaseSpine";
import { AudioManager } from "./Audio/AudioManager";
import { WANTED_POSTER_MANAGER_EVENT } from "./WantedPoster/WantedPosterManager";

const GAME_INTRO_ANIM_NAME = {
    IntroL: "GameIntro_L",
    IntroS: "GameIntro_S",
};

/**@ch Intro Spine 幀事件名稱*/
const GAME_INTRO_SPINE_EVENT = {
    /**@ch 觸發顯示懸賞令 x9999*/
    WantedOn: "Wanted_On",
};

const { ccclass, property } = _decorator;

/**@ch ReelUI Manager 事件*/
export const GAME_INTRO_MANAGER_EVENT = {
    /**
     * @ch 初始化
     * @param gameView 遊戲視窗
     */
    INIT: "GAME_INTRO_MANAGER_INIT",

    /**
     * @ch 展示node
     */
    SHOW_NODE : "GAME_INTRO_MANAGER_SHOW_NODE",

    /**
     * @ch 隱藏node
     */
    HIDE_NODE : "GAME_INTRO_MANAGER_HIDE_NODE",

    /**
     * @ch 更新UI
     */
    UPDATE_UI: "GAME_INTRO_MANAGER_UPDATE_UI",

    /**
     * @ch 展示intro
     * @param (必填) index 索引 0:橫 1:直 (0:只有一個方向時)
     * @param (選填) cb 完成後的callback
     */
    SHOW_INTRO: "GAME_INTRO_MANAGER_SHOW_INTRO",
}

@ccclass
export default class GameIntroManager extends Component
{
    //#region Constants
    /**
     * @ch 需要註冊的事件列表
     */
    private static readonly EVENTS_TO_REGISTER = [
        GAME_INTRO_MANAGER_EVENT.INIT,
        GAME_INTRO_MANAGER_EVENT.UPDATE_UI,
        GAME_INTRO_MANAGER_EVENT.SHOW_INTRO,
        GAME_INTRO_MANAGER_EVENT.SHOW_NODE,
        GAME_INTRO_MANAGER_EVENT.HIDE_NODE,
    ];
    //#endregion Constants

    //#region Properties
    @property( {
        type: BaseSpine,
        tooltip: "spine"
    } )
    private m_spines: BaseSpine[] = [];

    @property( {
        type: String,
        tooltip: "動畫key"
    } )
    private m_introAnimationKey_L: string = GAME_INTRO_ANIM_NAME.IntroL;

    @property( {
        type: String,
        tooltip: "動畫key"
    } )
    private m_introAnimationKey_S: string = GAME_INTRO_ANIM_NAME.IntroS;

    @property( {
        type: Boolean,
        tooltip: "是否要播音效"
    } )
    private m_isPlayAudioBgm: boolean = true;

    @property( {
        type: String,
        tooltip: "音效key",
        visible: function(this: any) { return this.m_isPlayAudioBgm; }
    } )
    private m_audioBgmKey: string = "Intro_Bgm";

    @property( {
        type: Number,
        tooltip: "音效延遲播放時間",
        visible: function(this: any) { return this.m_isPlayAudioBgm; }
    } )
    private m_audioBgmDelayTime: number = 0.5;

    @property( {
        type: Node,
        tooltip: "黑底遮罩"
    } )
    private m_blackMaskNode: Node = null;
    //#endregion Properties

    //#region Variables
    /**
     * @ch 遊戲視窗
     */
    private m_gameView: GameView = null;

    /**
     * @ch 最後一個 active 的索引
     */
    private m_lastActiveIndex: number = -1;

    /**
     * @ch 是否已經初始化
     */
    private m_isInitialized: boolean = false;
    //#endregion Variables

    //#region Lifecycle
    onLoad()
    {
        this.RegisterEvent();
    }

    onDestroy()
    {
        if (!this.m_isInitialized) return;
        this.UnregisterEvent();
        this.m_isInitialized = false;
        this.m_gameView = null;
        this.m_lastActiveIndex = -1;
    }
    //#endregion Lifecycle

    //#region Methods
    /**
     * @ch 初始化
     * @param gameView 遊戲視窗
     */
    Init( gameView: GameView )
    {
        if (this.m_isInitialized) return;
        this.m_isInitialized = true;
        this.m_gameView = gameView;

        // 主要是先停在intro動畫的開頭
        for ( let i = 0; i < this.m_spines.length; i++ )
        {
            const introAnimationKey = this.m_gameView.IsLandscape ? this.m_introAnimationKey_L : this.m_introAnimationKey_S;
            this.m_spines[ i ].Resume();
            this.m_spines[ i ].PlayAnimation(introAnimationKey, this.m_spines[ i ].Spine);
            this.m_spines[ i ].Pause();
        }
        this.SetSpineActive( -1, false );
        this.SetBlackMaskShow(true);
    }

    /**
     * @ch 註冊事件
     */
    private RegisterEvent()
    {
        GameIntroManager.EVENTS_TO_REGISTER.forEach(eventName => {
            eventManager.Register(eventName, this);
        });

        eventManager.Register(GAME_EVENT.DEVICE_ROTATION, this);
    }

    /**
     * @ch 取消註冊事件
     */
    private UnregisterEvent()
    {
        GameIntroManager.EVENTS_TO_REGISTER.forEach(eventName => {
            eventManager.UnRegister(eventName, this);
        });

        eventManager.UnRegister(GAME_EVENT.DEVICE_ROTATION, this);
    }

    /**
     * @ch 驗證事件名稱
     * @param event 事件名稱
     * @returns 是否有效
     */
    private ValidateEventName(event: string): boolean
    {
        if (!event || typeof event !== 'string') {
            warn('[GameIntroManager] OnEvent: 無效的事件名稱', event);
            return false;
        }
        return true;
    }

    /**
     * @ch 驗證 INIT 事件參數
     * @param args 事件參數
     * @returns 是否有效
     */
    private ValidateInitArgs(args: any[]): boolean
    {
        if (!args[0]) {
            warn('[GameIntroManager] INIT: 缺少 gameView 參數');
            return false;
        }
        return true;
    }

    /**
     * @ch 驗證 SHOW_INTRO 事件參數
     * @param args 事件參數
     * @returns 是否有效
     */
    private ValidateShowIntroArgs(args: any[]): boolean
    {
        if (typeof args[0] !== 'number') {
            warn('[GameIntroManager] SHOW_INTRO: 無效的索引參數', args[0]);
            return false;
        }
        return true;
    }

    /**
     * @ch 事件
     * @param event 事件名稱
     * @param args 事件參數
     */
    OnEvent( event: string, ...args: any[] )
    {
        if (!this.ValidateEventName(event)) {
            return;
        }

        switch (event)
        {
            case GAME_EVENT.DEVICE_ROTATION:
                this.UpdateUI();
                break;

            case GAME_INTRO_MANAGER_EVENT.INIT:
                if (this.ValidateInitArgs(args)) {
                    this.Init(args[0]);
                }
                break;

            case GAME_INTRO_MANAGER_EVENT.UPDATE_UI:
                this.UpdateUI();
                break;

            case GAME_INTRO_MANAGER_EVENT.SHOW_INTRO:
                if (this.ValidateShowIntroArgs(args)) {
                    this.ShowIntro(args[0], args[1]);
                }
                break;

            case GAME_INTRO_MANAGER_EVENT.SHOW_NODE:
                this.node.active = true;
                break;

            case GAME_INTRO_MANAGER_EVENT.HIDE_NODE:
                this.node.active = false;
                break;

            default:
                warn('[GameIntroManager] OnEvent: 未知的事件', event);
        }
    }

    /**
     * @ch 設置黑底遮罩顯示
     * @param isShow 是否顯示
     */
    private SetBlackMaskShow( isShow: boolean )
    {
        if (this.m_blackMaskNode) {
            this.m_blackMaskNode.active = isShow;
        }
    }

    /**
     * @ch 更新UI
     */
    private UpdateUI()
    {
        if ( !this.m_gameView || this.m_spines.length === 0 ) return;
        const activeIndex = this.m_spines.length > 1 ? (this.m_gameView.IsLandscape ? 0 : 1) : 0;
        if ( this.m_lastActiveIndex === activeIndex ) return;

        if ( this.m_spines.length > 1 && this.m_lastActiveIndex >= 0 && this.m_lastActiveIndex < this.m_spines.length )
        {
            this.SetSpineActive( this.m_lastActiveIndex, false );
        }
        this.SetSpineActive( activeIndex, true );
        this.m_lastActiveIndex = activeIndex;
    }

    /**
     * @ch 展示intro
     * @param index 索引 0:橫 1:直 (0:只有一個方向時)
     * @param (選填) cb 完成後的callback
     */
    private async ShowIntro(index: number, cb?: () => void) : Promise<void>
    {
        log("ShowIntro start");
        if (index < 0 || index >= this.m_spines.length)
        {
            cb?.();
            return;
        }

        this.scheduleOnce(this.PlayIntroBgm, this.m_audioBgmDelayTime);

        this.SetBlackMaskShow(false);

        Common.SetLockOrientation(true);
        let promises: Promise<void>[] = [];

        for (let i = index*this.m_spines.length/2; i < (index+1)*this.m_spines.length/2; i++) 
        {
            promises.push(new Promise<void>(async (resolve) => 
            {
                this.SetSpineActive( i, true );
                const spine = this.m_spines[ i ];
                if (spine) {
                    spine.Resume();
                    // 播放動畫
                    const introAnimationKey = this.m_gameView.IsLandscape ? this.m_introAnimationKey_L : this.m_introAnimationKey_S;
                    await spine.PlayAnimation(
                        introAnimationKey,
                        spine.Spine,
                        false,
                        undefined,
                        ( eventName ) => this.OnIntroSpineEvent( eventName )
                    );
                    resolve();
                }
            }));    
        }

        await Promise.all(promises);

        for (let i = index*this.m_spines.length/2; i < (index+1)*this.m_spines.length/2; i++) 
        {
            this.m_spines[ i ].SetSpineNodeActivity(false);
        }

        Common.SetLockOrientation(false);
        this.unschedule(this.PlayIntroBgm);
        cb?.();
        this.SetBlackMaskShow(true);
        this.node.active = false;
    }

    /**
     * @ch Intro Spine 幀事件回呼
     * 收到 Wanted_On 幀事件 → 派發 GAME_INTRO_COMPLETE，由 WantedPosterManager 顯示懸賞令 x9999
     * @param eventName Spine 幀事件名稱
     */
    private OnIntroSpineEvent( eventName: string )
    {
        if ( eventName === GAME_INTRO_SPINE_EVENT.WantedOn )
        {
            eventManager.Dispatch( WANTED_POSTER_MANAGER_EVENT.GAME_INTRO_COMPLETE );
        }
    }

    /**
     * @ch 播放intro bgm
     */
    private PlayIntroBgm()
    {
        if (!this.m_isPlayAudioBgm) return;
        AudioManager.Play(this.m_audioBgmKey);
    }

    /**
     * @ch 設置spine的active
     * @param index 索引 0:橫 1:直 負數:全部
     * @param isActive 
     */
    SetSpineActive( index: number, isActive: boolean )
    {
        if (index < 0) {
            this.m_spines.forEach(spine => spine.node.active = isActive);
            return;
        }
        if (index >= this.m_spines.length) {
            return;
        }
        this.m_spines[index].node.active = isActive;
    }
    //#endregion Methods
}

