30	@ccclass('DebugToolManager')
31	export class DebugToolManager extends Component {
32	
33	    /**@ch 啟用除錯功能（只在開發環境生效）*/
34	    private m_enableDebugTools: boolean = true;
35	
36	    /**@ch 最後一次 spin 的原始資料 */
37	    private m_lastSpinData: Uint8Array = null;
38	
39	    /**@ch 待用的除錯 Spin 資料（用於下次 Spin 時替換 Server 資料）*/
40	    private m_pendingSpinData: protocol.ar2pq9Proto.ISpinAck = null;
41	
42	    /**@ch 按鍵狀態追蹤 */
43	    private m_isCtrlPressed: boolean = false;
44	    private m_isAltPressed: boolean = false;
45	    private m_isShowProfiler: boolean = false;
46	
47	    //#region 生命週期
48	
49	    onLoad() {
50	        // 只在開發環境且非原生平台時啟用
51	        if (!this.IsDebugEnvironment()) {
52	            this.enabled = false;
53	            return;
54	        }
55	
56	        // 初始化 Profiler 顯示狀態（避免一開始狀態不同步）
57	        this.m_isShowProfiler = this.GetProfilerIsShowing();
58	
59	        this.RegisterKeyboardEvents();
60	        this.RegisterEventListeners();
61	        // this.ExposeToWindow();
62	
63	        log("🛠️ DebugToolManager 已啟用");
64	    }
65	
66	    onDestroy() {
67	        if (this.IsDebugEnvironment()) {
68	            this.UnregisterKeyboardEvents();
69	            this.UnregisterEventListeners();
70	            this.RemoveFromWindow();
71	        }
72	    }
73	
74	    //#endregion 生命週期
75	
76	    //#region 環境檢測
77	
78	    /**
79	     * @ch 檢查是否為除錯環境
80	     * @returns 是否為除錯環境
81	     */
82	    private IsDebugEnvironment(): boolean {
83	        // 只在 Web 環境啟用
84	        const isWebEnvironment = !sys.isNative && typeof window !== 'undefined';
85	
86	        return isWebEnvironment && this.m_enableDebugTools;
87	    }
88	
89	    //#endregion 環境檢測
90	
91	    //#region 視窗暴露
92	
93	    /**
94	     * @ch 暴露到全域 window 物件（使用命名空間避免衝突）
95	     */
96	    private ExposeToWindow(): void {
97	        if (typeof window !== 'undefined') {
98	            // 使用專案特定的命名空間
99	            (window as any)['__PIRATES_QUEEN_DEBUG__'] = this;
100	            log("💡 DebugToolManager 已暴露到全域，可使用: window.__PIRATES_QUEEN_DEBUG__");
101	            log("   - 下載資料: window.__PIRATES_QUEEN_DEBUG__.DownloadLastSpinData()");
102	            log("   - 上傳資料: window.__PIRATES_QUEEN_DEBUG__.UploadAndLoadSpinData()");
103	            log("   - 快捷鍵: Ctrl+Alt+D 下載資料 | Ctrl+Alt+U 上傳資料 | Ctrl+Alt+P 切換 Profiler");
104	        }
105	    }
106	
107	    /**
108	     * @ch 從 window 移除暴露
109	     */
110	    private RemoveFromWindow(): void {
111	        if (typeof window !== 'undefined') {
112	            delete (window as any)['__PIRATES_QUEEN_DEBUG__'];
113	        }
114	    }
115	
116	    //#endregion 視窗暴露
117	
118	    //#region 鍵盤事件
119	
120	    /**
121	     * @ch 註冊鍵盤事件
122	     */
123	    private RegisterKeyboardEvents(): void {
124	        input.on(Input.EventType.KEY_DOWN, this.OnKeyDown, this);
125	        input.on(Input.EventType.KEY_UP, this.OnKeyUp, this);
126	    }
127	
128	    /**
129	     * @ch 取消註冊鍵盤事件
130	     */
131	    private UnregisterKeyboardEvents(): void {
132	        input.off(Input.EventType.KEY_DOWN, this.OnKeyDown, this);
133	        input.off(Input.EventType.KEY_UP, this.OnKeyUp, this);
134	    }
135	
136	    /**
137	     * @ch 按鍵按下事件
138	     */
139	    private OnKeyDown(event: EventKeyboard): void {
140	        // 追蹤 Ctrl 鍵
141	        if (event.keyCode === KeyCode.CTRL_LEFT || event.keyCode === KeyCode.CTRL_RIGHT) {
142	            this.m_isCtrlPressed = true;
143	        }
144	        // 追蹤 Alt 鍵
145	        if (event.keyCode === KeyCode.ALT_LEFT || event.keyCode === KeyCode.ALT_RIGHT) {
146	            this.m_isAltPressed = true;
147	        }
148	
149	        // Ctrl+Alt+D: 下載最後一次 spin 資料
150	        if (event.keyCode === KeyCode.KEY_D && this.m_isCtrlPressed && this.m_isAltPressed) {
151	            this.DownloadLastSpinData();
152	        }
153	
154	        // Ctrl+Alt+U: 上傳並載入 spin 資料
155	        if (event.keyCode === KeyCode.KEY_U && this.m_isCtrlPressed && this.m_isAltPressed) {
156	            this.UploadAndLoadSpinData();
157	        }
158	
159	        // Ctrl+Alt+P: 顯示/隱藏性能分析器
160	        if (event.keyCode === KeyCode.KEY_P && this.m_isCtrlPressed && this.m_isAltPressed) {
161	            this.ShowProfiler();
162	        }
163	
164	        // if (event.keyCode === KeyCode.KEY_T ) {
165	        //     eventManager.Dispatch(BS_SPINE_CTRL_EVENT.PLAY, BS_SPINE_TYPE.CHARACTER, 'Aim', false,()=>{log('Aim 動畫播放完成')});
166	        //     eventManager.Dispatch(BS_SPINE_CTRL_EVENT.PLAY, BS_SPINE_TYPE.CANNON, 'S_Aim', false,()=>{log('Aim 動畫播放完成')});
167	
168	        // }
169	
170	        // if (event.keyCode === KeyCode.KEY_R ) {
171	        //     eventManager.Dispatch(RT_EVENT.AWARD_IN_RT);
172	        // }
173	
174	        // if (event.keyCode === KeyCode.KEY_F ) {
175	        //     eventManager.Dispatch(RT_EVENT.AWARD_OUT_RT);
176	        // }
177	
178	        // if (event.keyCode === KeyCode.KEY_U ) {
179	        //     stateManager.NextState(Game_Define.GameState.ENTER_FREE);
180	
181	        // }
182	
183	        // if (event.keyCode === KeyCode.KEY_L ) {
184	        //     stateManager.NextState(Game_Define.GameState.LEAVE_FREE);
185	        // }
186	    }
187	
188	    /**
189	     * @ch 按鍵釋放事件
190	     */
191	    private OnKeyUp(event: EventKeyboard): void {
192	        // 釋放 Ctrl 鍵
193	        if (event.keyCode === KeyCode.CTRL_LEFT || event.keyCode === KeyCode.CTRL_RIGHT) {
194	            this.m_isCtrlPressed = false;
195	        }
196	        // 釋放 Alt 鍵
197	        if (event.keyCode === KeyCode.ALT_LEFT || event.keyCode === KeyCode.ALT_RIGHT) {
198	            this.m_isAltPressed = false;
199	        }
200	    }
201	
202	    //#endregion 鍵盤事件
203	
204	    //#region 事件監聽
205	    /**
206	     * @ch 註冊事件監聽器
207	     */
208	    private RegisterEventListeners(): void {
209	        eventManager.Register(DEBUG_TOOL_EVENT.SPIN_DATA_RECEIVED, this);
210	        eventManager.Register(DEBUG_TOOL_EVENT.GET_PENDING_SPIN_DATA, this);
211	        eventManager.Register(DEBUG_TOOL_EVENT.CLEAR_PENDING_SPIN_DATA, this);
212	    }
213	
214	    /**
215	     * @ch 取消註冊事件監聽器
216	     */
217	    private UnregisterEventListeners(): void {
218	        eventManager.UnRegister(DEBUG_TOOL_EVENT.SPIN_DATA_RECEIVED, this);
219	        eventManager.UnRegister(DEBUG_TOOL_EVENT.GET_PENDING_SPIN_DATA, this);
220	        eventManager.UnRegister(DEBUG_TOOL_EVENT.CLEAR_PENDING_SPIN_DATA, this);
221	    }
222	
223	    /**
224	     * @ch 事件處理
225	     * @param event 事件名稱
226	     * @param args 事件參數
227	     */
228	    OnEvent(event: string, ...args: any[]): void {
229	        if ( !this.IsDebugEnvironment() )
230	        {
231	            return;
232	        }
233	
234	        switch (event) {
235	            case DEBUG_TOOL_EVENT.SPIN_DATA_RECEIVED:
236	                // 參數: (data: Uint8Array)
237	                if (args.length > 0 ) {
238	                    this.SaveSpinData(args[0]);
239	                } else {
240	                    error("❌ SPIN_DATA_RECEIVED 事件接收到無效的資料格式");
241	                }
242	                break;
243	
244	            case DEBUG_TOOL_EVENT.GET_PENDING_SPIN_DATA:
245	                if (typeof args[0] === "function") {
246	                    args[0](this.m_pendingSpinData);
247	                }
248	                break;
249	                
250	            case DEBUG_TOOL_EVENT.CLEAR_PENDING_SPIN_DATA:
251	                this.m_pendingSpinData = null;
252	                break;
253	        }
254	    }
255	    //#endregion 事件監聽
256	
257	    //#region 公開 API
258	
259	    /**
260	     * @ch 儲存 Spin 資料 (私有方法，透過事件觸發)
261	     * @param data Spin 原始資料
262	     */
263	    private SaveSpinData(data: Uint8Array): void {
264	        if (!this.IsDebugEnvironment()) {
265	            return;
266	        }
267	        this.m_lastSpinData = data;
268	        log(`💾 已儲存 Spin 資料: ${data.length} bytes`);
269	    }
270	
271	    /**
272	     * @ch 下載最後一次 spin 的原始資料為 .bin 檔案
273	     * @description 可在瀏覽器控制台手動調用：window.__PIRATES_QUEEN_DEBUG__.DownloadLastSpinData()
274	     */
275	    public DownloadLastSpinData(): void {
276	        if (!this.IsDebugEnvironment()) {
277	            log("⚠️ 除錯工具已停用");
278	            return;
279	        }
280	
281	        if (!this.m_lastSpinData) {
282	            log("⚠️ 尚無 spin 資料可供下載");
283	            return;
284	        }
285	
286	        try {
287	            // 產生時間戳記檔名
288	            const now = new Date();
289	            const timestamp = now.getFullYear().toString() +
290	                (now.getMonth() + 1).toString().padStart(2, '0') +
291	                now.getDate().toString().padStart(2, '0') + '_' +
292	                now.getHours().toString().padStart(2, '0') +
293	                now.getMinutes().toString().padStart(2, '0') +
294	                now.getSeconds().toString().padStart(2, '0');
295	            const filename = `spin_data_${timestamp}.bin`;
296	
297	            // 將 Uint8Array 轉換為 Blob
298	            const dataArray = new Uint8Array(this.m_lastSpinData);
299	            const blob = new Blob([dataArray], { type: 'application/octet-stream' });
300	
301	            // 建立下載連結
302	            const url = URL.createObjectURL(blob);
303	            const link = document.createElement('a');
304	            link.href = url;
305	            link.download = filename;
306	
307	            // 觸發下載
308	            document.body.appendChild(link);
309	            link.click();
310	
311	            // 清理
312	            document.body.removeChild(link);
313	            URL.revokeObjectURL(url);
314	
315	            log(`✅ Spin 資料已下載: ${filename} (${this.m_lastSpinData.length} bytes)`);
316	        } catch (err) {
317	            error(`❌ 下載失敗: ${err}`);
318	        }
319	    }
320	
321	    /**
322	     * @ch 上傳並載入 .bin 檔案（用於重放 spin 資料）
323	     * @description 可在瀏覽器控制台手動調用：window.__PIRATES_QUEEN_DEBUG__.UploadAndLoadSpinData()
324	     */
325	    public UploadAndLoadSpinData(): void {
326	        if (!this.IsDebugEnvironment()) {
327	            log("⚠️ 除錯工具已停用");
328	            return;
329	        }
330	
331	        try {
332	            // 建立隱藏的 file input
333	            const input = document.createElement('input');
334	            input.type = 'file';
335	            input.accept = '.bin';
336	            input.style.display = 'none';
337	
338	            input.onchange = (e: any) => {
339	                const file = (e.target as HTMLInputElement).files?.[0];
340	                if (!file) {
341	                    log("⚠️ 未選擇檔案");
342	                    return;
343	                }
344	
345	                log(`📁 讀取檔案: ${file.name} (${file.size} bytes)`);
346	
347	                const reader = new FileReader();
348	                reader.onload = (event: ProgressEvent<FileReader>) => {
349	                    try {
350	                        const arrayBuffer = event.target?.result as ArrayBuffer;
351	                        if (!arrayBuffer) {
352	                            error("❌ 讀取檔案失敗：無法取得資料");
353	                            return;
354	                        }
355	
356	                        // 轉換為 Uint8Array
357	                        const uint8Array = new Uint8Array(arrayBuffer);
358	                        log(`📦 成功讀取 ${uint8Array.length} bytes 資料`);
359	
360	                        // 解析 SpinAck 資料
361	                        this.ParseAndApplySpinData(uint8Array);
362	
363	                    } catch (parseError) {
364	                        error(`❌ 解析檔案失敗: ${parseError}`);
365	                    }
366	                };
367	
368	                reader.onerror = () => {
369	                    error(`❌ 讀取檔案失敗: ${reader.error}`);
370	                };
371	
372	                reader.readAsArrayBuffer(file);
373	            };
374	
375	            // 觸發檔案選擇
376	            document.body.appendChild(input);
377	            input.click();
378	            document.body.removeChild(input);
379	
380	        } catch (err) {
381	            error(`❌ 上傳失敗: ${err}`);
382	        }
383	    }
384	
385	    /**
386	     * @ch 啟用/停用除錯工具
387	     * @param enable 是否啟用
388	     */
389	    public SetEnableDebugTools(enable: boolean): void {
390	        this.m_enableDebugTools = enable;
391	        log(`${enable ? '✅ 已啟用' : '❌ 已停用'} 除錯工具功能`);
392	    }
393	
394	    /**
395	     * @ch 取得待用的 Spin 資料
396	     * @returns 待用的 SpinAck 資料，若無則回傳 null
397	     */
398	    public GetPendingSpinData(): protocol.ar2pq9Proto.ISpinAck | null {
399	        return this.m_pendingSpinData;
400	    }
401	
402	    /**
403	     * @ch 清除待用的 Spin 資料
404	     */
405	    public ClearPendingSpinData(): void {
406	        if (this.m_pendingSpinData) {
407	            log("🗑️ 已清除待用的除錯 Spin 資料");
408	            this.m_pendingSpinData = null;
409	        }
410	    }
411	
412	    //#endregion 公開 API
413	
414	    //#region 私有方法
415	
416	    /**
417	     * @ch 解析並暫存 spin 資料（等待下次 Spin 時使用）
418	     * @param data Uint8Array 格式的 spin 資料
419	     */
420	    private ParseAndApplySpinData(data: Uint8Array): void {
421	        try {
422	            // 解碼為 SpinAck
423	            const spinAck: protocol.ar2pq9Proto.ISpinAck = protocol.ar2pq9Proto.SpinAck.decode(data);
424	            log("✅ SpinAck 解碼成功", spinAck);
