import { sp, AudioClip } from "cc";
import { soundAudioManager } from "../../Managers";

export interface ISpineKitOptions
{
    spine: sp.Skeleton;
    aniName: string;
    loop?: boolean;
    trackIdx?: number;
    eventCb?: ( eventName: string ) => void;
    needRest?: boolean;
}

export default class SpineKit
{
    private static m_cancelCbs: { [ spineNname: string ]: { [ animNname: string ]: () => void } } = {};
    private static m_audioMaps = {};

    static ForceCancel( spineNname: string, animName: string )
    {
        this.m_cancelCbs?.[ spineNname ][ animName ]?.();
    }

    /**
     * @ch 設定 Spine 的音效對照表
     * @param skeletonData spine骨架資料
     * @param audioMap 音效對照表 key:動畫名稱 value:音效檔
     */
    static SetAudioClips( spineName: string, audioMap: { [ key: string ]: AudioClip } )
    {
        this.m_audioMaps[ spineName ] = audioMap;
    }

    static PlayAnimation( options: sp.Skeleton | ISpineKitOptions, aniName?: string, loop: boolean = false, trackIdx: number = 0, eventCb?: ( eventName: string ) => void, needRest: boolean = true ): Promise<boolean>
    {
        let spine: sp.Skeleton;
        if ( !( options instanceof sp.Skeleton ) )
        {
            aniName = options.aniName;
            loop = options.loop ?? false;
            trackIdx = options.trackIdx ?? 0;
            eventCb = options.eventCb ?? null;
            needRest = options.needRest ?? true;
            spine = options.spine;
        }
        else
        {
            spine = options;
        }
        if ( !aniName )
        {
            throw new Error( "aniName is required" );
        }

        if ( spine.skeletonData?.name )
        {
            const audioMap = this.m_audioMaps[ spine.skeletonData.name ];
            if ( audioMap && audioMap[ aniName ] )
            {
                soundAudioManager.Play( audioMap[ aniName ] );
            }
        }

        this.m_cancelCbs[ spine.name ] = {};
        //檢查是否有mix設定
        let canClear: boolean = true;
        let state: sp.spine.AnimationState = spine.getState();
        if ( state )
        {
            let current: sp.spine.TrackEntry = state.expandToIndex( trackIdx );
            if ( current )
            {
                let key: string = current.animation.name + "." + aniName;
                let value = state.data.animationToMixTime[ key ];
                canClear = value === undefined;
            }
        }
        //沒有mix設定才可清除
        if ( canClear )
        {
            spine.clearTrack( trackIdx );
            if ( needRest )
            {
                spine.setToSetupPose();
            }
        }
        let trackEntry = spine.setAnimation( trackIdx, aniName, loop );
        return new Promise<boolean>( ( resolve ) =>
        {
            this.m_cancelCbs[ spine.name ][ aniName ] = () =>
            {
                resolve( true );
            };
            if ( trackEntry )
            {
                spine.setTrackEventListener( trackEntry, ( entry: sp.spine.TrackEntry, event: sp.spine.Event ) =>
                {
                    if ( !trackEntry || trackEntry.animation.name != entry.animation.name ) return;
                    eventCb?.( event.data.name );
                } );
                spine.setTrackCompleteListener( trackEntry, ( entry: sp.spine.TrackEntry ) =>
